mapper.select:
SELECT p.project_id, p.project_code, p.project_name, p.project_type, p.procurement_mode, p.owner_org_id, owner_department.department_name AS owner_org_name, p.agent_org_id, agent_department.department_name AS agent_org_name, p.manager_employee_id, manager_employee.actual_name AS manager_employee_name, p.status, p.budget_amount, p.publish_time, p.archive_time, p.remark, p.version, p.create_time, p.update_time, IFNULL(lot_summary.lot_count, 0) AS lot_count FROM t_bid_project p LEFT JOIN t_department owner_department ON owner_department.department_id = p.owner_org_id LEFT JOIN t_department agent_department ON agent_department.department_id = p.agent_org_id LEFT JOIN t_employee manager_employee ON manager_employee.employee_id = p.manager_employee_id LEFT JOIN ( SELECT project_id, COUNT(1) AS lot_count FROM t_bid_lot WHERE deleted_flag = 0 GROUP BY project_id ) lot_summary ON lot_summary.project_id = p.project_id
p.deleted_flag = #{queryForm.deletedFlag}
AND ( p.project_code LIKE CONCAT('%', #{queryForm.keyword}, '%') OR p.project_name LIKE CONCAT('%', #{queryForm.keyword}, '%') )
AND p.project_type = #{queryForm.projectType}
AND p.procurement_mode = #{queryForm.procurementMode}
AND p.status = #{queryForm.status}
AND p.owner_org_id = #{queryForm.ownerOrgId}
ORDER BY p.project_id DESC

SELECT project_id, project_code, project_name, status FROM t_bid_project WHERE deleted_flag = 0
AND status = #{status}
ORDER BY project_id DESC
